mapper.select:
SELECT e.id, e.order_id, e.favorite_part, e.improvement_suggestion, e.expectation, e.overall_score, e.arrangement_score, e.attraction_score, e.knowledge_immersion_score, e.is_deleted, e.create_time, e.update_time, o.museum_id, od.activity_id, am.activity_name FROM evaluation e
LEFT JOIN `order` o ON o.id = e.order_id AND (o.is_deleted = 0 OR o.is_deleted IS NULL)
LEFT JOIN order_detail od ON od.order_id = e.order_id AND (od.is_deleted = 0 OR od.is_deleted IS NULL)
LEFT JOIN activity_manage am ON am.id = od.activity_id AND (am.is_deleted = 0 OR am.is_deleted IS NULL) WHERE e.is_deleted = 0
AND e.order_id = #{vo.orderId}
AND o.museum_id = #{vo.museumId}
AND am.activity_name LIKE CONCAT('%', #{vo.activityName}, '%')
AND e.overall_score = #{vo.overallScore}
AND e.create_time BETWEEN #{startDateTime} AND #{endDateTime}
AND e.create_time >= #{startDateTime}
AND e.create_time <= #{endDateTime}
ORDER BY e.id DESC
